import{_ as a,o as t,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"72. Study Leave","description":"","frontmatter":{"title":"72. Study Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","study-leave","employment"]},"headers":[],"relativePath":"ebas/mspp/leave/72-study-leave.md","filePath":"ebas/mspp/leave/72-study-leave.md"}'),r={name:"ebas/mspp/leave/72-study-leave.md"};function l(p,e,n,i,d,u){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_72-study-leave" tabindex="-1">72. Study Leave <a class="header-anchor" href="#_72-study-leave" aria-label="Permalink to &quot;72. Study Leave&quot;">​</a></h1><p><strong>a.</strong> Paid study leave for post-graduate study shall be available to Full Time and accordance with this clause must apply in writing to the Employer as early as possible prior to the proposed leave date. The Employee’s request should include details of the course and institution in which the Employee is enrolled or proposes to enrol and details of the relevance of the course to the Employee’s employment.</p><p><strong>b.</strong> The Employer will notify the Employee of whether their request for study leave has been approved within 7 days of the application being made.</p><p><strong>c.</strong> Study leave as provided for in clause 72a is for 4 hours per week up to 26 weeks per annum.</p><p><strong>d.</strong> Paid study leave may be taken as mutually agreed by, for example, 4 hours per week, 8 hours per fortnight or blocks of 38 hours.</p><p><strong>e.</strong> A part-time Employee will be paid study leave on a pro-rata basis.</p><p>Plain language terms: education leave.</p>',7)])])}const y=a(r,[["render",l]]);export{m as __pageData,y as default};
